

export const getTableUniqueKey = ({mode, id, dbId}) => {
    //assuming dbId is generated by frontend at create mode and is part of table object otherwise use correct object to get db id
    if(!id || !mode) 
     throw new Error("error in getTableUniqueKey func. id or mode is missing");
    if(mode === "create") {
        if(!dbId)
        throw new Error("error in getTableUniqueKey func. dbId is missing");
        return id + "_" + dbId;
    }
    if(mode === "edit") 
        return id;
}

